mapper.select:
SELECT mll.user_id as userId, mll.browser as browser, mll.operate_system as operateSystem,
mll.create_time as createTime, mu.nickname as userName, mll.ip as region, mll.login_way as loginWay,
mll.tenant_id tenantId,mll.tenant_name tenantName
FROM md_tenant_login_log mll
LEFT JOIN md_user mu ON mll.user_id = mu.id
WHERE mll.app_id = #{loginLogParam.appKey}

    AND mll.tenant_id = #{loginLogParam.tenantId}


    AND mll.create_time > #{loginLogParam.beginTime}


    AND #{loginLogParam.endTime} > mll.create_time


    AND mll.user_id = #{loginLogParam.id}


    AND (mu.nickname like concat('%',#{loginLogParam.user},'%')
    OR mu.nickname like LOWER (concat('%',#{loginLogParam.user},'%'))
    OR mu.nickname like UPPER (concat('%',#{loginLogParam.user},'%')))






    AND mll.login_way IN

        #{way}


ORDER BY mll.create_time DESC
